#traverse(root, effects, render_effects) {
	root.f ^= CLEAN;

	var effect = root.first;

	while (effect !== null) {
		var flags = effect.f;
		var is_branch = (flags & (BRANCH_EFFECT | ROOT_EFFECT)) !== 0;
		var is_skippable_branch = is_branch && (flags & CLEAN) !== 0;

		var skip = is_skippable_branch || (flags & INERT) !== 0 || this.#skipped_branches.has(effect);

		if (!skip && effect.fn !== null) {
			if (is_branch) {
				effect.f ^= CLEAN;
			} else if ((flags & EFFECT) !== 0) {
				effects.push(effect);
			} else if (async_mode_flag && (flags & (RENDER_EFFECT | MANAGED_EFFECT)) !== 0) {
				render_effects.push(effect);
			} else if (is_dirty(effect)) {
				if ((flags & BLOCK_EFFECT) !== 0) this.#maybe_dirty_effects.add(effect);
				update_effect(effect);
			}

			var child = effect.first;

			if (child !== null) {
				effect = child;
				continue;
			}
		}

		while (effect !== null) {
			var next = effect.next;

			if (next !== null) {
				effect = next;
				break;
			}

			effect = effect.parent;
		}
	}
}

function binding_fixture(name: string, props: BindingProperty): string {
	// Map declared `valid_elements` to a concrete element + minimal attrs
	// so the compiler accepts the binding.
	const tag = (props.valid_elements ?? ['div'])[0];

	const reactive = `let v = $state();`;

	if (tag === 'svelte:window') {
		return `<script>${reactive}</script><svelte:window bind:${name}={v} />`;
	}
	if (tag === 'svelte:document') {
		return `<script>${reactive}</script><svelte:document bind:${name}={v} />`;
	}
	if (tag === 'input') {
		// `bind:checked` and `bind:group` require type="checkbox" | "radio"
		const type =
			name === 'checked' || name === 'indeterminate'
				? ' type="checkbox"'
				: name === 'group'
					? ' type="radio" value="a"'
					: name === 'files'
						? ' type="file"'
						: '';
		return `<script>${reactive}</script><input${type} bind:${name}={v} />`;
	}
	if (tag === 'details') {
		return `<script>${reactive}</script><details bind:${name}={v}><summary>x</summary></details>`;
	}

	return `<script>${reactive}</script><${tag} bind:${name}={v}></${tag}>`;
}

constructor(opts: DialogRootStateOpts, parent: DialogRootState | null) {
	this.opts = opts;
	this.parent = parent;
	this.depth = parent ? parent.depth + 1 : 0;
	this.handleOpen = this.handleOpen.bind(this);
	this.handleClose = this.handleClose.bind(this);

	this.contentPresence = new PresenceManager({
		ref: boxWith(() => this.contentNode),
		open: this.opts.open,
		enabled: true,
		onComplete: () => {
			this.opts.onOpenChangeComplete.current(this.opts.open.current);
		},
	});

	this.overlayPresence = new PresenceManager({
		ref: boxWith(() => this.overlayNode),
		open: this.opts.open,
		enabled: true,
	});

	watch(
		() => this.opts.open.current,
		(isOpen) => {
			if (!this.parent) return;
			if (isOpen) {
				this.parent.incrementNested();
			} else {
				this.parent.decrementNested();
			}
		},
		{ lazy: true }
	);

	onDestroyEffect(() => {
		if (this.opts.open.current) {
			this.parent?.decrementNested();
		}
	});
}

export const usePortal = ((el, target = 'body') => {
	let targetEl;

	if (!isHTMLElement(target) && typeof target !== 'string') {
		return {
			destroy: noop,
		};
	}

	async function update(newTarget: PortalConfig = 'body') {
		target = newTarget;

		if (typeof target === 'string') {
			targetEl = document.querySelector(target);
			if (targetEl === null) {
				await tick();
				targetEl = document.querySelector(target);
			}
			if (targetEl === null) {
				throw new Error(`No element found matching css selector: "${target}"`);
			}
		} else if (target instanceof HTMLElement) {
			targetEl = target;
		} else {
			throw new TypeError(
				`Unknown portal target type: ${
					target === null ? 'null' : typeof target
				}. Allowed types: string (CSS selector) or HTMLElement.`
			);
		}
		el.dataset.portal = '';
		targetEl.appendChild(el);
		el.hidden = false;
	}

	function destroy() {
		el.remove();
	}

	update(target);
	return {
		update,
		destroy,
	};
}) satisfies Action<HTMLElement, PortalConfig>;

