export function createSync<Stores extends Record<string, Writable<unknown>>>(stores: Stores) {
	let setters = {} as {
		[K in keyof Stores]?: (value: WritableValue<Stores[K]>) => void;
	};
	keys(stores).forEach((key) => {
		const store = stores[key];
		effect(store, (value) => {
			if (key in setters) {
				// eslint-disable-next-line @typescript-eslint/no-explicit-any
				setters[key]?.(value as any);
			}
		});
	});

	return keys(stores).reduce(
		(acc, key) => {
			type Value = WritableValue<Stores[typeof key]>;
			return {
				...acc,
				[key]: function sync(value: Value, setter?: (value: Value) => void) {
					stores[key].update((p) => {
						if (dequal(p, value)) return p;
						return value;
					});
					if (setter) {
						setters = { ...setters, [key]: setter };
					}
				},
			};
		},
		{} as {
			[K in keyof Stores]: (
				value: WritableValue<Stores[K]>,
				setter?: (value: WritableValue<Stores[K]>) => void
			) => void;
		}
	);
}

private transformShorthand(
    snapshot: SvelteDocumentSnapshot,
    location: TsRenameLocation,
    newName: string
): TsRenameLocation | undefined {
    const shorthand = this.getBindingOrAttrShorthand(snapshot, location.range.start);
    if (shorthand) {
        if (shorthand.isBinding) {
            // bind:|foo| -> bind:|newName|={foo}
            return {
                ...location,
                prefixText: '',
                suffixText: `={${shorthand.id.name}}`
            };
        } else {
            return {
                ...location,
                range: {
                    // {|foo|} -> |{foo|}
                    start: {
                        line: location.range.start.line,
                        character: location.range.start.character - 1
                    },
                    end: location.range.end
                },
                // |{foo|} -> newName=|{foo|}
                newName: shorthand.id.name,
                prefixText: `${newName}={`,
                suffixText: ''
            };
        }
    }
}

export function showNode(id, options = {}) {
  const { expand = true, select = true, focus = true } = options;

  for (const child of nodes) {
    const path = findNodeById(child, id);

    if (path) {
      const ids = path.map((node) => node.id);
      const lastId = ids[ids.length - 1];

      if (expand) {
        const ancestorIds = ids.slice(0, -1);
        for (const ancestorId of ancestorIds) {
          expandedIdsSet.add(ancestorId);
        }
        expandedIds = Array.from(expandedIdsSet);
        lastExpandedIdsRef = expandedIds;
      }

      if (select) {
        activeId = lastId;
        const targetNode = path[path.length - 1];
        if (multiselect && multiselectMode !== "node") {
          selectedIds = multiselectExpansionIds(targetNode, multiselectMode);
        } else {
          selectedIds = [lastId];
        }
      }

      if (focus) {
        tick().then(() => {
          ref?.querySelector(`[id="${CSS.escape(lastId)}"]`)?.focus();
        });
      }

      break;
    }
  }
}

function adjustIfNecessary(diagnostic: Diagnostic, isSvelte5Plus: boolean): Diagnostic {
    if (
        diagnostic.code === DiagnosticCode.ARG_TYPE_X_NOT_ASSIGNABLE_TO_TYPE_Y &&
        diagnostic.message.includes('ConstructorOfATypedSvelteComponent')
    ) {
        return {
            ...diagnostic,
            message:
                diagnostic.message +
                '\n\nPossible causes:\n' +
                '- You use the instance type of a component where you should use the constructor type\n' +
                '- Type definitions are missing for this Svelte Component. ' +
                (isSvelte5Plus
                    ? ''
                    : 'If you are using Svelte 3.31+, use SvelteComponentTyped to add a definition:\n' +
                      '  import type { SvelteComponentTyped } from "svelte";\n' +
                      '  class ComponentName extends SvelteComponentTyped<{propertyName: string;}> {}')
        };
    }

    if (diagnostic.code === DiagnosticCode.MODIFIERS_CANNOT_APPEAR_HERE) {
        return {
            ...diagnostic,
            message:
                diagnostic.message +
                '\nIf this is a declare statement, move it into <script context="module">..</script>'
        };
    }

    return diagnostic;
}

function handleTriggerKeydown(
	e: KeyboardEvent,
	node: HTMLElement | null,
	root: PaginationRootState
) {
	if (!node || !root.opts.ref.current) return;
	const items = root.getPageTriggerNodes();
	const nextButton = root.getButtonNode("next");
	const prevButton = root.getButtonNode("prev");

	if (prevButton) {
		items.unshift(prevButton);
	}
	if (nextButton) {
		items.push(nextButton);
	}

	const currentIndex = items.indexOf(node);

	const dir = getElemDirection(root.opts.ref.current);

	const { nextKey, prevKey } = getDirectionalKeys(dir, root.opts.orientation.current);

	const loop = root.opts.loop.current;

	const keyToIndex = {
		[nextKey]: currentIndex + 1,
		[prevKey]: currentIndex - 1,
		[kbd.HOME]: 0,
		[kbd.END]: items.length - 1,
	};

	let itemIndex = keyToIndex[e.key];
	if (itemIndex === undefined) return;
	e.preventDefault();

	if (itemIndex < 0 && loop) {
		itemIndex = items.length - 1;
	} else if (itemIndex === items.length && loop) {
		itemIndex = 0;
	}

	const itemToFocus = items[itemIndex];
	if (!itemToFocus) return;

	itemToFocus.focus();
}

